171→Add to `src/wow/protocol/guild.ts`:
172→
173→```ts
174→export const GuildEventCode = {
175→  PROMOTION: 0,
176→  DEMOTION: 1,
177→  MOTD: 2,
178→  JOINED: 3,
179→  LEFT: 4,
180→  REMOVED: 5,
181→  LEADER_IS: 6,
182→  LEADER_CHANGED: 7,
183→  DISBANDED: 8,
184→  SIGNED_ON: 12,
185→  SIGNED_OFF: 13,
186→} as const;
187→
188→const HAS_TRAILING_GUID = new Set([
189→  GuildEventCode.JOINED,
190→  GuildEventCode.LEFT,
191→  GuildEventCode.SIGNED_ON,
192→  GuildEventCode.SIGNED_OFF,
193→]);
194→
195→export type GuildEventRaw = {
196→  eventType: number;
197→  params: string[];
198→};
199→
200→export function parseGuildEvent(r: PacketReader): GuildEventRaw {
201→  const eventType = r.uint8();
202→  const paramCount = r.uint8();
203→  const params: string[] = [];
204→  for (let i = 0; i < paramCount; i++) {
205→    params.push(r.cString());
206→  }
207→  if (HAS_TRAILING_GUID.has(eventType as any)) {
208→    r.uint64LE();
209→  }
210→  return { eventType, params };
211→}
212→```
213→
214→Note: The `as any` cast is needed because `eventType` is `number` while the Set contains literal values. This is the simplest approach — the set membership check works at runtime regardless.
