765→```ts
766→function formatGuildEvent(event: GuildEvent): string | undefined {
767→  switch (event.type) {
768→    case "guild-roster":
769→      return `[guild] Roster updated: ${event.roster.members.length} members`;
770→    case "promotion":
771→      return `[guild] ${event.officer} promoted ${event.member} to ${event.rank}`;
772→    case "demotion":
773→      return `[guild] ${event.officer} demoted ${event.member} to ${event.rank}`;
774→    case "motd":
775→      return `[guild] MOTD: ${event.text}`;
776→    case "joined":
777→      return `[guild] ${event.name} has joined the guild`;
778→    case "left":
779→      return `[guild] ${event.name} has left the guild`;
780→    case "removed":
781→      return `[guild] ${event.officer} removed ${event.member} from the guild`;
782→    case "leader_is":
783→      return `[guild] ${event.name} is the guild leader`;
784→    case "leader_changed":
785→      return `[guild] ${event.oldLeader} has made ${event.newLeader} the new guild leader`;
786→    case "disbanded":
787→      return "[guild] Guild has been disbanded";
788→    case "signed_on":
789→      return `[guild] ${event.name} has come online`;
790→    case "signed_off":
791→      return `[guild] ${event.name} has gone offline`;
792→  }
793→}
794→
795→function formatGuildEventObj(
796→  event: GuildEvent,
797→): Record<string, unknown> | undefined {
798→  switch (event.type) {
799→    case "guild-roster":
800→      return {
801→        type: "GUILD_ROSTER_UPDATED",
802→        sender: "",
803→        message: `${event.roster.members.length} members`,
804→      };
805→    case "promotion":
806→      return {
807→        type: "GUILD_PROMOTION",
808→        officer: event.officer,
809→        member: event.member,
810→        rank: event.rank,
811→      };
812→    case "demotion":
813→      return {
814→        type: "GUILD_DEMOTION",
815→        officer: event.officer,
816→        member: event.member,
817→        rank: event.rank,
818→      };
819→    case "motd":
820→      return { type: "GUILD_MOTD", text: event.text };
821→    case "joined":
822→      return { type: "GUILD_JOINED", name: event.name };
823→    case "left":
824→      return { type: "GUILD_LEFT", name: event.name };
825→    case "removed":
826→      return {
827→        type: "GUILD_REMOVED",
828→        member: event.member,
829→        officer: event.officer,
830→      };
831→    case "leader_is":
832→      return { type: "GUILD_LEADER_IS", name: event.name };
833→    case "leader_changed":
834→      return {
835→        type: "GUILD_LEADER_CHANGED",
836→        oldLeader: event.oldLeader,
837→        newLeader: event.newLeader,
838→      };
839→    case "disbanded":
840→      return { type: "GUILD_DISBANDED" };
841→    case "signed_on":
842→      return { type: "GUILD_SIGNED_ON", name: event.name };
843→    case "signed_off":
844→      return { type: "GUILD_SIGNED_OFF", name: event.name };
845→  }
846→}
847→
848→export function onGuildEvent(
849→  event: GuildEvent,
850→  events: RingBuffer<EventEntry>,
851→  log: SessionLog,
852→): void {
853→  const text = formatGuildEvent(event);
854→  const obj = formatGuildEventObj(event);
855→  if (obj) {
856→    events.push({ text, json: JSON.stringify(obj) });
857→    log.append(obj as LogEntry).catch(() => {});
858→  }
859→}
860→```
